mapper.select:
SELECT CAST(a.id AS CHAR) as id,baidu_url,category_id,cover_image, FROM_UNIXTIME(a.create_time, '%Y-%m-%d %H:%i:%s') as create_time,details,intro,properties,a.sort,a.status,title,view_num, b.`name` as category_name
FROM materials a inner join material_categories b on a.`category_id` = b.id


        and a.category_id = #{categoryId}


ORDER BY a.sort asc
limit #{startIndex},#{pageSize}
